[{"operationName":"dashboard","variables":{},"query":"query dashboard {
  viewer {
    id
    firstName
    lastName
    ... on Member {
      tosAccepted
      matches {
        type
        ...matchListItem
        __typename
      }
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    __typename
  }
}

fragment matchListItem on Match {
  id
  isBye
  status
  scoresheet
  startTime
  isMine
  isPaid
  isScored
  isFinalized
  isPlayoff
  description
  tableNumber
  results {
    homeAway
    points {
      total
      __typename
    }
    __typename
  }
  timeZone {
    id
    name
    __typename
  }
  location {
    id
    name
    address {
      id
      name
      __typename
    }
    __typename
  }
  home {
    id
    name
    number
    isMine
    __typename
  }
  away {
    id
    name
    number
    isMine
    __typename
  }
  league {
    id
    isMine
    slug
    isElectronicPaymentsEnabled
    __typename
  }
  orderItems {
    id
    order {
      id
      member {
        id
        firstName
        lastName
        __typename
      }
      __typename
    }
    __typename
  }
  division {
    id
    scheduleInEdit
    isTournament
    __typename
  }
  __typename
}
"}]

[{"operationName":"dashboardNews","variables":{},"query":"fragment leagueNewsFrag on League {
  id
  isDefault
  news {
    ...newsFrag
    __typename
  }
  __typename
}

query dashboardNews {
  viewer {
    id
    ... on Member {
      leagues {
        ...leagueNewsFrag
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        ...leagueNewsFrag
        __typename
      }
      __typename
    }
    __typename
  }
  national: league(id: 589) {
    id
    news {
      ...newsFrag
      __typename
    }
    __typename
  }
}

fragment newsFrag on News {
  id
  title
  body
  featuredImage
  createdDate
  updatedDate
  effectiveDate
  isSticky
  league {
    id
    slug
    __typename
  }
  __typename
}
"},{"operationName":"leagueEvents","variables":{"limit":3,"offset":0},"query":"fragment leagueWithScheduleFrag on League {
  id
  name
  slug
  schedule(offset: $offset, limit: $limit) {
    ... on Tournament {
      id
      name
      startTime
      hostLocation {
        id
        address {
          id
          name
          __typename
        }
        __typename
      }
      __typename
    }
    ... on OtherEvent {
      id
      name
      startTime
      address {
        id
        name
        latitude
        longitude
        __typename
      }
      __typename
    }
    __typename
  }
  __typename
}

query leagueEvents($offset: Int!, $limit: Int!) {
  league(id: 589) {
    ...leagueWithScheduleFrag
    __typename
  }
  viewer {
    id
    ... on Member {
      leagues {
        ...leagueWithScheduleFrag
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        ...leagueWithScheduleFrag
        __typename
      }
      __typename
    }
    __typename
  }
}
